DROP TABLE IF EXISTS `vls_video_record`;
CREATE TABLE `vls_video_record`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Primary key ID',
  `tenant_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Tenant ID',
  `stream` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'stream',
  `device_id` bigint NOT NULL COMMENT 'Device ID',
  `device_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Device Name',
  `file_name` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Video File Name',
  `file_path` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Video File Path',
  `file_size` bigint NULL DEFAULT 0 COMMENT 'File size (bytes)',
  `url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'Playback URL',
  `duration` int NULL DEFAULT 0 COMMENT 'Video Duration (seconds)',
  `format` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'mp4' COMMENT 'Video Format',
  `record_start_time` timestamp NOT NULL COMMENT 'Recording start time',
  `record_end_time` timestamp NOT NULL COMMENT 'Recording end time',
  `record_date` date NOT NULL COMMENT 'Recording date (used for grouping by date)',
  `record_status` enum('recording','completed','failed','deleted') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'recording' COMMENT 'Recording status',
  `thumbnail_path` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Thumbnail path',
  `create_user` bigint NULL DEFAULT NULL COMMENT 'Created by',
  `create_dept` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'Create department',
  `create_time` datetime NULL DEFAULT NULL COMMENT 'Creation time',
  `update_user` bigint NULL DEFAULT NULL COMMENT 'Modified by',
  `update_time` datetime NULL DEFAULT NULL COMMENT 'Modification time',
  `status` int NULL DEFAULT 1 COMMENT 'Status',
  `is_deleted` int NULL DEFAULT 0 COMMENT 'Whether deleted',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_device_id`(`device_id` ASC) USING BTREE COMMENT 'Device ID index',
  INDEX `idx_record_date`(`record_date` ASC) USING BTREE COMMENT 'Recording date index',
  INDEX `idx_record_start_time`(`record_start_time` ASC) USING BTREE COMMENT 'Recording start time index',
  INDEX `idx_record_status`(`record_status` ASC) USING BTREE COMMENT 'Recording status index',
  INDEX `idx_device_date`(`device_id` ASC, `record_date` ASC) USING BTREE COMMENT 'Device date composite index'
) ENGINE = InnoDB AUTO_INCREMENT = 2028272270022111235 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'Video recording records table' ROW_FORMAT = DYNAMIC;

