  `event_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'pending' COMMENT 'Event status: pending-Pending, processing-Processing, completed-Completed, closed-Closed',
