  `latitude` decimal(10, 6) NULL DEFAULT NULL COMMENT 'Latitude',
  `height_position` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'ground' COMMENT 'Height position (high altitude/ground/underground/other)',
  `address` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Detail Address',
  `region` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Division selection',
  `creator` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Created by',
  `tag` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Device Tag',
  `algorithm_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Algorithm ID',
  `push_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Push address',
  `is_public` int NULL DEFAULT 1 COMMENT 'Whether public: 0-No, 1-Yes',
  `create_user` bigint NULL DEFAULT NULL COMMENT 'Created by',
  `create_dept` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'Create department',
  `create_time` datetime NULL DEFAULT NULL COMMENT 'Creation time',
