  INDEX `idx_status`(`status` ASC) USING BTREE COMMENT 'Device status index',
  INDEX `idx_device_type`(`device_type` ASC) USING BTREE COMMENT 'Device type index',
  INDEX `idx_status_type`(`status` ASC, `device_type` ASC) USING BTREE COMMENT 'Composite index of status and type'
