  `onnx_model_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'onnx model file path',
  `rknn_model_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'rknn model file path',
  `int8_rknn_model_output_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'int8 rknn model output path',
  `accuracy` decimal(5, 2) NULL DEFAULT NULL COMMENT 'Model accuracy',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'Model description',
  `download_count` int NULL DEFAULT 0 COMMENT 'Download count',
  `deploy_count` int NULL DEFAULT 0 COMMENT 'Deployment count',
  `publish_time` datetime NULL DEFAULT NULL COMMENT 'Publish time',
  `create_user` bigint NULL DEFAULT NULL COMMENT 'Created by',
  `create_dept` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'Create department',
  `create_time` datetime NULL DEFAULT NULL COMMENT 'Creation time',
  `update_user` bigint NULL DEFAULT NULL COMMENT 'Modified by',
  `update_time` datetime NULL DEFAULT NULL COMMENT 'Modification time',
  `status` int NULL DEFAULT 1 COMMENT 'Status: 0 draft, 1 testing, 2 published',
  `is_deleted` int NULL DEFAULT 0 COMMENT 'Whether deleted',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_algorithm_id`(`algorithm_id` ASC) USING BTREE,
  INDEX `idx_training_id`(`training_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2029088467952111618 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'Algorithm model table' ROW_FORMAT = DYNAMIC;

