DROP TABLE IF EXISTS `vls_algorithm_annotation`;
CREATE TABLE `vls_algorithm_annotation`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Annotation ID',
  `tenant_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'Tenant ID',
  `annotation_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'Annotation Name',
  `annotation_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'Annotation type: object_detection-object detection, image_classification-image classification, instance_segmentation-instance segmentation, semantic_segmentation-semantic segmentation',
  `dataset_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'Dataset path',
  `total_count` int NULL DEFAULT 0 COMMENT 'Total quantity',
  `annotated_count` int NULL DEFAULT 0 COMMENT 'Annotated quantity',
  `annotation_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'none' COMMENT 'Annotation status: none-unannotated, partial-partially annotated, completed-completed',
  `progress` int NULL DEFAULT 0 COMMENT 'Annotation Progress Percentage',
  `annotation_rules` json NULL COMMENT 'Annotation Rule',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'Remarks',
  `create_user` bigint NULL DEFAULT NULL COMMENT 'Created by',
  `create_dept` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'Create department',
  `create_time` datetime NULL DEFAULT NULL COMMENT 'Creation time',
  `update_user` bigint NULL DEFAULT NULL COMMENT 'Modified by',
  `update_time` datetime NULL DEFAULT NULL COMMENT 'Modification time',
  `status` int NULL DEFAULT 1 COMMENT 'Status',
  `is_deleted` int NULL DEFAULT 0 COMMENT 'Whether deleted',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_annotation_type`(`annotation_type` ASC) USING BTREE,
  INDEX `idx_annotation_status`(`annotation_status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2010645279972614147 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'Algorithm annotation data table' ROW_FORMAT = DYNAMIC;

