-- ----------------------------
-- Table structure for vls_algorithm
-- ----------------------------
DROP TABLE IF EXISTS `vls_algorithm`;
CREATE TABLE `vls_algorithm`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'Primary key ID',
  `tenant_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Tenant ID',
  `repository_id` bigint NOT NULL COMMENT 'Algorithm repository ID to which it belongs',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Algorithm name',
  `category` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Algorithm category (object detection, instance segmentation, image classification, keypoint detection, rotated object detection, etc.)',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Algorithm description',
  `image_url` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'Algorithm image URL',
  `pt_model_file_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Model file path',
  `onnx_model_file_path` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Model file path',
  `config_params` json NULL COMMENT 'Algorithm configuration parameters (JSON format)',
  `input_format` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Input format (image, video, etc.)',
  `output_format` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'Output format (bbox, mask, keypoint, etc.)',
  `gpu_required` int NULL DEFAULT 0 COMMENT 'Whether GPU is required: 0-No, 1-Yes',
  `is_system` int NULL DEFAULT NULL COMMENT 'Whether it is a system preset algorithm: 0-No, 1-Yes',
  `create_user` bigint NULL DEFAULT NULL COMMENT 'Created by',
  `create_dept` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'Create department',
  `create_time` datetime NULL DEFAULT NULL COMMENT 'Creation time',
  `update_user` bigint NULL DEFAULT NULL COMMENT 'Modified by',
  `update_time` datetime NULL DEFAULT NULL COMMENT 'Modification time',
  `status` int NULL DEFAULT 1 COMMENT 'Status',
  `is_deleted` int NULL DEFAULT 0 COMMENT 'Whether deleted',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_algorithm_repository`(`repository_id` ASC) USING BTREE,
  INDEX `idx_algorithm_name`(`name` ASC) USING BTREE,
  INDEX `idx_algorithm_category`(`category` ASC) USING BTREE,
  CONSTRAINT `vls_algorithm_ibfk_1` FOREIGN KEY (`repository_id`) REFERENCES `vls_algorithm_repository` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 2006206115765698563 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'Algorithm table' ROW_FORMAT = DYNAMIC;

